external_knowledge:
; Average speed is a measure of the total distance traveled divided by the total time taken; 
; Fuel consumption refers to the amount of fuel used during navigation; 
; Weather conditions like sunny, rainy, morning, and afternoon can significantly impact navigation.

sql:
SELECT average_speed, distance_traveled
FROM navigation_history
WHERE navigation_status = 'completed';

SELECT vehicle_id, AVG(average_speed) AS avg_speed
FROM navigation_history
WHERE vehicle_id = 0;

SELECT average_speed
FROM navigation_history
WHERE navigation_id = 1;

SELECT AVG(average_traffic_volume) AS avg_traffic_volume
FROM time_of_day
WHERE time_name = 'morning' AND peak_hours = 1;
